async (params, browser) => {
  // Open models search
  await browser.open(`https://www.kaggle.com/models?search=${params.query}`)

  // Wait for model results
  await browser.waitForSelector('a[href*=\'/models/\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll for more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract models
  const results = await browser.evaluate(`const results = []; const seen = new Set(); document.querySelectorAll('a[href*="/models/"]').forEach(a => { const href = a.getAttribute('href') || ''; if (!href.match(/^\/models\/[^/]+\/[^/]+/) || seen.has(href)) return; seen.add(href); const title = a.textContent.trim(); if (!title || title.length > 200 || title.length < 3) return; const parent = a.closest('li') || a.parentElement; const metadata = parent ? Array.from(parent.querySelectorAll('span, p')).map(e => e.textContent.trim()).filter(t => t.length > 3 && t !== title).slice(0, 3) : []; results.push({ title: title.substring(0, 200), url: 'https://www.kaggle.com' + href, metadata: metadata.join(' | ') }); }); return { query: '' + params.query + '', result_count: results.length, results: results.slice(0, 15) };`)

  return results
}
